#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char s[100005];
        scanf("%s", s);
        int n = strlen(s);
        int *L = (int*)malloc((n+1) * sizeof(int));
        int *R = (int*)malloc((n+1) * sizeof(int));
        L[0] = 1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == '<') L[i+1] = L[i] + 1;
            else if (s[i] == '=') L[i+1] = L[i];
            else L[i+1] = 1; // '>'
        }
        R[n] = 1;
        for (int i = n-1; i >= 0; --i) {
            if (s[i] == '>') R[i] = R[i+1] + 1;
            else if (s[i] == '=') R[i] = R[i+1];
            else R[i] = 1; // '<'
        }
        int ans = 1;
        for (int i = 0; i <= n; ++i) {
            int cur = L[i] > R[i] ? L[i] : R[i];
            if (cur > ans) ans = cur;
        }
        printf("%d\n", ans);
        free(L);
        free(R);
    }
    return 0;
}

