import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            String s = br.readLine().trim();
            int n = s.length();
            int[] L = new int[n+1];
            int[] R = new int[n+1];
            L[0] = 1;
            for (int i = 0; i < n; ++i) {
                char c = s.charAt(i);
                if (c == '<') L[i+1] = L[i] + 1;
                else if (c == '=') L[i+1] = L[i];
                else L[i+1] = 1; // '>'
            }
            R[n] = 1;
            for (int i = n-1; i >= 0; --i) {
                char c = s.charAt(i);
                if (c == '>') R[i] = R[i+1] + 1;
                else if (c == '=') R[i] = R[i+1];
                else R[i] = 1; // '<'
            }
            int ans = 1;
            for (int i = 0; i <= n; ++i) {
                ans = Math.max(ans, Math.max(L[i], R[i]));
            }
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }
}

