import sys

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        s = data[idx].strip()
        idx += 1
        n = len(s)
        L = [0]*(n+1)
        R = [0]*(n+1)
        L[0] = 1
        for i,ch in enumerate(s):
            if ch == '<':
                L[i+1] = L[i] + 1
            elif ch == '=':
                L[i+1] = L[i]
            else:  # '>'
                L[i+1] = 1
        R[n] = 1
        for i in range(n-1, -1, -1):
            ch = s[i]
            if ch == '>':
                R[i] = R[i+1] + 1
            elif ch == '=':
                R[i] = R[i+1]
            else:  # '<'
                R[i] = 1
        ans = 1
        for i in range(n+1):
            cur = L[i] if L[i] > R[i] else R[i]
            if cur > ans:
                ans = cur
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

